def flatten(lst):
    result = []
    for item in lst:
        if isinstance(item, list):
            flatten(item)
        else:
            result.append(item)
    return result

print(flatten([1, [2, [3, 4], 5], 6]))  # Should print [1, 2, 3, 4, 5, 6]

assert flatten([1, [2, [3, 4], 5], 6]) == [1, 2, 3, 4, 5, 6]
assert flatten([]) == []
assert flatten([[[[1]]]]) == [1]
